 579→    #[test]
 580→    fn cycle_nodes_appear_in_final_topo_layer() {
 581→        // A → B → A, C (no deps)
 582→        let registry = make_registry(&[
 583→            ("src/a.ts", "A", vec!["B"]),
 584→            ("src/a.ts", "B", vec!["A"]),
 585→            ("src/a.ts", "C", vec![]),
 586→        ]);
 587→        let graph = CallGraph::from_registry(&registry);
 588→
 589→        let layers = graph.topological_layers();
 590→        // C is a leaf → layer 0; A and B are in a cycle → final layer
 591→        assert_eq!(layers.len(), 2);
 592→        assert_eq!(layers[0], vec!["src/a.ts::C"]);
 593→        assert!(layers[1].contains(&"src/a.ts::A".to_string()));
 594→        assert!(layers[1].contains(&"src/a.ts::B".to_string()));
 595→    }
