248→/// Run a multi-function scan in dependency order.
249→///
250→/// Builds a call graph from the analyses, determines test order (leaves first),
251→/// then explores each function. Callees that have already been tested provide
252→/// mock configurations derived from their behavior maps.
253→pub async fn scan(
254→    frontend: &mut Frontend,
255→    analyses: &[FunctionAnalysis],
256→    config: &ScanConfig,
257→) -> Result<ScanResult, ScanError> {
258→    let call_graph = CallGraph::from_analyses(analyses);
259→    let order_entries = call_graph.test_order()?;
260→
261→    // Flatten test order entries into layers for stratum filtering.
262→    let all_layers = build_layers(&order_entries, &call_graph);
263→
264→    // Apply stratum filter: only explore functions in selected layers.
265→    let filtered_layers: Vec<Vec<String>> = if let Some(ref spec) = config.stratum {
266→        let max_layer = if all_layers.is_empty() { 0 } else { all_layers.len() - 1 };
267→        let range = crate::stratum::resolve_range(spec, max_layer)?;
268→        crate::stratum::filter_layers(&all_layers, &range)
269→            .into_iter()
270→            .map(|(_, funcs)| funcs.clone())
271→            .collect()
272→    } else {
273→        all_layers
274→    };
275→
276→    // Flatten filtered layers into function names for iteration.
277→    let test_order: Vec<String> = filtered_layers
278→        .into_iter()
279→        .flat_map(|layer| layer.into_iter())
280→        .collect();
281→
282→    let analysis_map: HashMap<&str, &FunctionAnalysis> =
283→        analyses.iter().map(|a| (a.name.as_str(), a)).collect();
284→
285→    let mut behavior_maps: HashMap<String, BehaviorMap> = HashMap::new();
286→    let mut function_results: Vec<FunctionResult> = Vec::new();
287→    let mut skipped_functions: Vec<SkippedFunction> = Vec::new();
288→    let mut deep_fingerprints: HashMap<String, String> = HashMap::new();
289→
290→    // Load checkpoint for resume support.
291→    let scan_id = crate::checkpoint::ScanCheckpoint::compute_scan_id(
292→        &config.file_map.values().map(|s| s.as_str()).collect::<Vec<_>>(),
293→    );
294→    let mut checkpoint = match &config.resume_path {
295→        Some(path) => {
296→            match crate::checkpoint::ScanCheckpoint::load(path) {
297→                Ok(Some(cp)) if cp.scan_id == scan_id => cp,
298→                Ok(Some(_)) => {
299→                    log::info!("checkpoint scan_id mismatch, starting fresh");
300→                    crate::checkpoint::ScanCheckpoint::new(scan_id)
301→                }
302→                Ok(None) => crate::checkpoint::ScanCheckpoint::new(scan_id),
303→                Err(e) => {
304→                    log::warn!("failed to load checkpoint: {e}, starting fresh");
305→                    crate::checkpoint::ScanCheckpoint::new(scan_id)
306→                }
307→            }
308→        }
309→        None => crate::checkpoint::ScanCheckpoint::new(scan_id),
310→    };
311→
312→    // Load the interesting input pool for cross-function seed sharing.
313→    let mut input_pool = config
314→        .pool_path
315→        .as_ref()
316→        .and_then(|p| interesting_pool::load_pool(p).ok().flatten())
317→        .unwrap_or_default();
318→    input_pool.epoch += 1;
319→
320→    for func_name in &test_order {
321→        let analysis = match analysis_map.get(func_name.as_str()) {
322→            Some(a) => *a,
323→            None => continue,
324→        };
325→
326→        // Compute shallow fingerprint, then deep fingerprint incorporating callees.
327→        let shallow_fingerprint = compute_fingerprint_for_function(func_name, analysis, config);
328→        let callees = call_graph.callees(func_name);
329→        let current_deep_fp = shallow_fingerprint.as_ref().map(|sfp| {
330→            crate::fingerprint::compute_deep_fingerprint(sfp, &deep_fingerprints, &callees)
331→        });
332→
333→        // Check resume checkpoint first (uses deep FP).
334→        if let (Some(cache), Some(dfp)) = (&config.cache, &current_deep_fp)
335→            && checkpoint.is_completed(func_name, dfp, cache)
336→            && let Ok(Some(cached_map)) = cache.load(func_name)
337→        {
338→            behavior_maps.insert(func_name.clone(), cached_map);
339→            deep_fingerprints.insert(func_name.clone(), dfp.clone());
340→            skipped_functions.push(SkippedFunction {
341→                function_name: func_name.clone(),
342→                reason: "resumed from checkpoint".into(),
343→                category: SkipCategory::Expected,
344→            });
345→            continue;
346→        }
347→
348→        // Check cache freshness using deep fingerprint.
349→        if let (Some(cache), Some(dfp)) = (&config.cache, &current_deep_fp)
350→            && let Ok(true) = cache.is_fresh(func_name, dfp)
351→            && let Ok(Some(cached_map)) = cache.load(func_name)
352→        {
353→            behavior_maps.insert(func_name.clone(), cached_map);
354→            deep_fingerprints.insert(func_name.clone(), dfp.clone());
355→            skipped_functions.push(SkippedFunction {
356→                function_name: func_name.clone(),
357→                reason: "unchanged (fingerprint match)".into(),
358→                category: SkipCategory::Expected,
359→            });
360→            continue;
361→        }
362→
363→        // Try loading a cached behavior map for callees that aren't yet in memory.
364→        if let Some(ref cache) = config.cache {
365→            for dep in &analysis.dependencies {
366→                if !behavior_maps.contains_key(&dep.symbol)
367→                    && let Ok(Some(cached)) = cache.load(&dep.symbol)
368→                {
369→                    behavior_maps.insert(dep.symbol.clone(), cached);
370→                }
371→            }
372→        }
373→
374→        // Build mocks from callees that have already been tested.
375→        let mut mocks: Vec<MockConfig> = Vec::new();
376→        let mut mocks_used: Vec<MockUsage> = Vec::new();
377→
378→        for callee in &callees {
379→            if let Some(bmap) = behavior_maps.get(callee) {
380→                mocks.push(mock_config_from_behavior_map(bmap));
381→                mocks_used.push(MockUsage {
382→                    name: callee.clone(),
383→                    source: MockSource::CachedBehaviorMap,
384→                });
385→            }
386→        }
387→
388→        // Generate auto-mocks for remaining unmocked dependencies.
389→        let auto_mocks = crate::auto_mock::generate_auto_mocks(
390→            &analysis.dependencies,
391→            None,
392→            &config.mock_overrides,
393→            &mocks,
394→        );
395→        for am in &auto_mocks {
396→            mocks_used.push(MockUsage {
397→                name: am.symbol.clone(),
398→                source: MockSource::TypeAwareStub,
399→            });
400→        }
401→        mocks.extend(auto_mocks);
402→        mocks_used.sort_by(|a, b| a.name.cmp(&b.name));
403→
404→        let file = config
405→            .file_map
406→            .get(func_name)
407→            .cloned()
408→            .unwrap_or_default();
409→
410→        let pool_seeds = crate::input_gen::pool_to_candidate_inputs(&analysis.params, &input_pool);
411→
412→        let candidate_inputs = load_config_candidate_inputs(
413→            func_name,
414→            &config.config_dir,
415→            config.max_iterations_per_function,
416→            config.timeout_per_fn.as_secs(),
417→        );
418→
419→        let explore_config = ExploreConfig {
420→            file,
421→            max_iterations: config.max_iterations_per_function,
422→            seed: config.seed,
423→            mocks,
424→            setup_file: None,
425→            setup_mode: crate::config::SetupMode::PerFunction,
426→            value_sources: vec![],
427→            capabilities: crate::orchestrator::FrontendCapabilities::default(),
428→            user_seeds: vec![],
429→            candidate_inputs,
430→            pool_seeds,
431→            project_root: config.project_root.clone(),
432→            loop_buckets: explorer::LoopBuckets::default(),
433→            timeout_explore: config.timeout_explore,
434→        };
435→
436→        let exploration = explorer::explore_function(frontend, analysis, &explore_config).await?;
437→
438→        // Harvest interesting inputs into the cross-function pool.
439→        interesting_pool::harvest_from_exploration(
440→            &mut input_pool,
441→            &exploration.raw_results,
442→            &analysis.params,
443→            func_name,
444→        );
445→
446→        // Run the Analyze stage to produce behavior map and coverage metrics.
447→        let mut analyze_out = crate::pipeline::analyze(&exploration, analysis);
448→        analyze_out.behavior_map.fingerprint = current_deep_fp.clone();
449→
450→        // Persist the behavior map to cache for reuse across runs.
451→        if let Some(ref cache) = config.cache {
452→            let _ = cache.store(&analyze_out.behavior_map);
453→        }
454→
455→        // Record deep fingerprint for downstream functions.
456→        if let Some(ref dfp) = current_deep_fp {
457→            deep_fingerprints.insert(func_name.clone(), dfp.clone());
458→            checkpoint.mark_completed(func_name, dfp);
459→        }
460→
461→        // Save checkpoint periodically.
462→        if let Some(ref path) = config.resume_path {
463→            let _ = checkpoint.save(path);
464→        }
465→
466→        // Compute behavior coverage for each callee (cross-function concern).
467→        let records: Vec<ExecutionRecord> = exploration
468→            .raw_results
469→            .iter()
470→            .map(|(inputs, result)| execution_record_from_result(func_name, inputs, result))
471→            .collect();
472→        let mut behavior_coverage: Vec<BehaviorCoverage> = Vec::new();
473→        for callee in &callees {
474→            if let Some(callee_map) = behavior_maps.get(callee) {
475→                let coverage = BehaviorCoverage::compute(func_name, &records, callee_map);
476→                behavior_coverage.push(coverage);
477→            }
478→        }
479→
480→        behavior_maps.insert(func_name.clone(), analyze_out.behavior_map.clone());
481→
482→        function_results.push(FunctionResult {
483→            function_name: func_name.clone(),
484→            exploration,
485→            behavior_map: analyze_out.behavior_map,
486→            behavior_coverage,
487→            mocks_used,
488→            coverage_metrics: analyze_out.coverage_metrics,
489→        });
490→    }
491→
492→    // Save the interesting input pool if configured.
493→    if let Some(ref pool_path) = config.pool_path
494→        && let Err(e) = interesting_pool::save_pool(&input_pool, pool_path)
495→    {
496→        log::warn!("failed to save interesting pool: {e}");
497→    }
498→
499→    Ok(ScanResult {
500→        function_results,
501→        test_order,
502→        skipped_functions,
503→        sampling: None,
504→    })
505→}
