pub enum MockSource {
    /// Mock derived from a previously computed behavior map.
    CachedBehaviorMap,
    /// Auto-generated type-aware stub (no behavior map available).
    TypeAwareStub,
    /// Auto-mock for a function excluded by `--stratum` filtering.
    StratumExcluded,
